import { createClient } from "@supabase/supabase-js";
import { redirect } from "next/navigation";

async function createProduct(formData: FormData) {
  "use server";

    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
      const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

        if (!supabaseUrl) {
            throw new Error("Falta NEXT_PUBLIC_SUPABASE_URL");
              }

                if (!serviceRoleKey) {
                    throw new Error("Falta SUPABASE_SERVICE_ROLE_KEY");
                      }

                        const supabase = createClient(supabaseUrl, serviceRoleKey);

                          const title = String(formData.get("title") || "").trim();
                            const description = String(formData.get("description") || "").trim();
                              const category = String(formData.get("category") || "").trim();
                                const provider = String(formData.get("provider") || "").trim();
                                  const planName = String(formData.get("plan_name") || "").trim();
                                    const durationDays = Number(formData.get("duration_days") || 30);
                                      const price = Number(formData.get("price") || 0);

                                        const accountEmail = String(formData.get("account_email") || "").trim();
                                          const deliveryReference = String(formData.get("delivery_reference") || "").trim();
                                            const deliveryNotes = String(formData.get("delivery_notes") || "").trim();

                                              if (!title || !category || !price) {
                                                  throw new Error("Faltan title, category o price");
                                                    }

                                                      const { data: product, error: productError } = await supabase
                                                          .from("products")
                                                              .insert({
                                                                    title,
                                                                          description,
                                                                                category,
                                                                                      provider,
                                                                                            plan_name: planName,
                                                                                                  duration_days: durationDays,
                                                                                                        price,
                                                                                                              status: "active",
                                                                                                                  })
                                                                                                                      .select("id")
                                                                                                                          .single();

                                                                                                                            if (productError || !product) {
                                                                                                                                throw new Error(
                                                                                                                                      `PRODUCT_INSERT_ERROR: ${productError?.message || "No se pudo crear el producto"}`
                                                                                                                                          );
                                                                                                                                            }

                                                                                                                                              // El inventario inicial NO debe bloquear la creación del producto
                                                                                                                                                if (accountEmail || deliveryReference || deliveryNotes) {
                                                                                                                                                    const { error: inventoryError } = await supabase.from("inventory").insert({
                                                                                                                                                          product_id: product.id,
                                                                                                                                                                account_email: accountEmail || null,
                                                                                                                                                                      delivery_reference: deliveryReference || null,
                                                                                                                                                                            notes: deliveryNotes || null,
                                                                                                                                                                                  status: "available",
                                                                                                                                                                                      });

                                                                                                                                                                                          if (inventoryError) {
                                                                                                                                                                                                console.error("INVENTORY_INSERT_ERROR:", inventoryError.message);
                                                                                                                                                                                                      // No lanzamos error: el producto ya quedó creado
                                                                                                                                                                                                          }
                                                                                                                                                                                                            }

                                                                                                                                                                                                              redirect("/admin/products");
                                                                                                                                                                                                              }

